where.trim:
a.id=b.special_id
and b.id=c.session_id and c.attr_id=e.id and e.pid=d.id and a.mch_id=mch.id
    and a.store_id = #{store_id}
and c.status = #{status}
and d.mch_id = #{goodsMchId}
and a.is_settlement = #{is_settlement}
and ( mch.name=#{key} or d.product_title like concat('%',#{key},'%') )
and ( a.name=concat('%',#{auctionKey},'%') or b.name like
    concat('%',#{auctionKey},'%') )



        #{id}

mapper.select:
select d.product_title goodsName,b.name sessionName,a.name specialName,mch.name mchName,c.starting_amt,c.mark_up_amt,c.id acId,c.status,c.is_show,c.price currentPrice,e.attribute,b.id sessionId,c.status goodsStatus,c.sNo, b.status sessionStatus,a.status specialStatus,a.end_date specialEndDate,a.start_date specialStartDate,a.id specialId from lkt_auction_special a,lkt_auction_session b,lkt_auction_product c,lkt_product_list d,lkt_configure e,lkt_mch mch
c.add_date ${add_date_sort},
limit #{pageStart},#{pageEnd}

mapper.sql:
and a.recycle = 0
and a.id = #{id}
and a.is_show = 1 and c.is_open = 1
and a.title like concat('%',#{title},'%')
and b.user_id = #{user_id_my}
and a.store_id = #{store_id}


        #{status,jdbcType=INTEGER}


and a.invalid_time   >   #{invalid_systime}

where.trim:
and a.recovery=0 and a.is_show=1
and s.store_id = #{store_id}
and s.type = #{type}
and s.id = #{specialId}
and b.id = #{sessionId}
and goods.mch_id = #{mch_id}
and goods.mch_id != #{not_mchId}
and goods.product_title like concat('%',#{goodsName},'%')
and (goods.product_title like concat('%',#{key},'%') or mch.name like concat('%',#{key},'%'))
and b.status in

    #{status}



    and a.starting_amt >= #{start_price}


    and a.starting_amt <= #{end_price}


    and goods.product_class LIKE CONCAT('%-', #{cid},'-%')

mapper.select:
SELECT a.id, c.img, a.goods_price, a.price, a.starting_amt, a.mark_up_amt, cls.pname className, c.attribute, b.status sessionStatus, a.status, goods.product_title, a.is_show, mch.name mchName, c.img, DATE_FORMAT(b.end_date, '%Y-%m-%d %H:%i:%s' ) AS end_date, (select count(1) from lkt_auction_record x where x.auction_id=a.id) outNum, DATE_FORMAT(b.start_date, '%Y-%m-%d %H:%i:%s' ) AS start_date, a.goods_id, mch.id as mchId FROM lkt_auction_product AS a INNER JOIN lkt_configure AS c ON a.attr_id = c.id INNER JOIN lkt_auction_session b ON b.id = a.session_id AND b.recovery = a.recovery INNER JOIN lkt_auction_special s ON s.id = b.special_id AND s.recovery = a.recovery INNER JOIN lkt_product_list goods ON goods.id = c.pid LEFT JOIN lkt_product_class cls ON cls.cid = substring_index( substring_index( goods.product_class, '-', 2 ), '-', - 1 ) LEFT JOIN lkt_mch mch ON mch.id = goods.mch_id
a.sort desc, a.add_date ${add_date_sort}, outNum ${count}, a.starting_amt ${price}, s.start_date ${date}, end_date ${end_date},
limit #{pageStart},#{pageEnd}

SELECT t.currenPrice, t.passed_status, t.acId, t.product_title, t.goodsStatus, t.special_id, t.sessionStatus, t.end_date, t.start_date, t.price, t.starting_amt, t.img, t.sNo, t.attribute, t.mchId FROM ( SELECT DISTINCT a.price currenPrice, b.passed_status, b.id acId, c.product_title, b.`status` goodsStatus, d.special_id, d.`status` sessionStatus, d.end_date, d.start_date, b.price, b.starting_amt, e.img, b.sNo, e.attribute, c.mch_id mchId, ROW_NUMBER() OVER (PARTITION BY a.auction_id ORDER BY a.add_time DESC) AS rn FROM lkt_auction_record a INNER JOIN lkt_auction_product b ON a.auction_id = b.id INNER JOIN lkt_product_list c ON b.goods_id = c.id INNER JOIN lkt_auction_session d ON b.session_id = d.id INNER JOIN lkt_configure e ON b.attr_id = e.id WHERE b.recovery = 0 AND c.recycle = 0 AND c.recycle = b.recovery AND c.recycle = d.recovery AND c.recycle = e.recycle
AND a.user_id = #{userId}
AND b.`status` IN
#{status}
AND d.`status` = #{sessionStatus}
AND b.user_id = #{finalUserId}
AND b.user_id != #{notMy}
AND (b.user_id != #{notMy02} OR (b.`status` = 3 AND b.passed_status = 2))
AND b.passed_status = #{passedStatus}
) t WHERE t.rn = 1 LIMIT #{start}, #{end}
